      PROCEDURE CGPF$SET_SYSDATE_PARAM IS
-- inialise the SYSDATE parameter to current date

BEGIN
  :CG$P_SYSDATE := SYSDATE;
END;

      function BeforePForm return boolean is
begin
  -- inialise the SYSDATE parameter to current date
  CGPF$SET_SYSDATE_PARAM;

  return (TRUE);
end;

      function CUENTAFormula return Char is
begin
  RETURN	:MCF_CFO_CCC_CLI_PER_TID_CODIGO||'-'||		:MCF_CFO_CCC_CLI_PER_NUM_IDEN||'-'||		TO_CHAR(:MCF_CFO_CCC_NUMERO_CUENTA)||'-'||		:FON_MNEMONICO||		TO_CHAR(:MCF_CFO_CODIGO);
end;

      function AfterReport return boolean is
   CURSOR C_TABLA IS
      SELECT 'X' 
      FROM   USER_TABLES
      WHERE  TABLE_NAME = 'TS_MOVIMIENTOS_FONDOS';
   COND1   VARCHAR2(1);
begin
  OPEN C_TABLA;
  FETCH C_TABLA INTO COND1;
  CLOSE C_TABLA;
  IF NVL(COND1,' ') = 'X' THEN
  	SRW.DO_SQL('DROP TABLE TS_MOVIMIENTOS_FONDOS');
  END IF;
  return (TRUE);
end;

      function CF_RETENCIONFormula return Number is
   CURSOR C_RETENCION IS
      SELECT DMF_RENDIMIENTOS
            ,DMF_RETENCION
            ,DMF_DIFERENCIA_CAMBIO          
      FROM   DETALLES_MOVIMIENTOS_FONDOS
      WHERE  DMF_MCF_CONSECUTIVO = :MCF_CONSECUTIVO; --rhenao	
/*      WHERE  DMF_MCF_CFO_CCC_CLI_PER_NUM_ID = :MCF_CFO_CCC_CLI_PER_NUM_IDEN
      AND    DMF_MCF_CFO_CCC_CLI_PER_TID_CO = :MCF_CFO_CCC_CLI_PER_TID_CODIGO
      AND    DMF_MCF_CFO_CCC_NUMERO_CUENTA = :MCF_CFO_CCC_NUMERO_CUENTA
      AND    DMF_MCF_CFO_FON_CODIGO = :MCF_CFO_FON_CODIGO
      AND    DMF_MCF_CFO_CODIGO = :MCF_CFO_CODIGO 
      AND    DMF_MCF_FECHA = :MCF_FECHA; */ --rhenao
   DMF1   C_RETENCION%ROWTYPE;
begin
   IF :FON_TIPO = 'A' AND
      :FON_BMO_MNEMONICO != 'PESOS' THEN
      OPEN C_RETENCION;
      FETCH C_RETENCION INTO DMF1;
      CLOSE C_RETENCION;
      :CP_RENDIMIENTOS := NVL(DMF1.DMF_RENDIMIENTOS + DMF1.DMF_DIFERENCIA_CAMBIO,0);
      RETURN NVL(DMF1.DMF_RETENCION,0);
   ELSE
      RETURN NVL(:MCF_SALDO_RETEFUENTE5,0);
   END IF;
end;

