      function BeforeReport return boolean is
   CURSOR C_TABLA IS
      SELECT 'X' 
      FROM   USER_TABLES
      WHERE  TABLE_NAME = 'TS_MOVIMIENTOS_FONDOS';
   COND1   VARCHAR2(1);

   CURSOR C_FONDO IS
      SELECT FON_TIPO
            ,FON_BMO_MNEMONICO
      FROM   FONDOS
      WHERE  FON_CODIGO = :QUE_FONDO;
   FON1  C_FONDO%ROWTYPE;
begin
  IF :QTIPO = 'D' THEN
     :Q_TIPOMOV := 'D';
     :Q_TIPODESC := 'Despues de Distribucion';
  ELSIF :QTIPO = 'C' THEN
     OPEN C_FONDO;
     FETCH C_FONDO INTO FON1;
     CLOSE C_FONDO;
     IF FON1.FON_TIPO = 'A' AND
        FON1.FON_BMO_MNEMONICO != 'PESOS' THEN
        :Q_TIPOMOV := 'CR';
     ELSE
        :Q_TIPOMOV := 'C';
     END IF;
     :Q_TIPODESC :='Despues de Capitalizacion';
  ELSIF :QTIPO = 'O' THEN
     :Q_TIPOMOV := 'O';     	
  END IF;

  OPEN C_TABLA;
  FETCH C_TABLA INTO COND1;
  CLOSE C_TABLA;
  IF NVL(COND1,' ') = 'X' THEN
  	SRW.DO_SQL('DROP TABLE TS_MOVIMIENTOS_FONDOS');
  END IF;
  SRW.DO_SQL(' CREATE TABLE TS_MOVIMIENTOS_FONDOS ' ||
         ' STORAGE ' ||
         ' ( ' ||
         ' INITIAL 16384 ' ||
         ' NEXT 16384 ' ||
         ' PCTINCREASE 0 ' ||
         ' MINEXTENTS 1 ' ||
         ' MAXEXTENTS 9999 ' ||
         ' ) ' ||
         ' TABLESPACE DESARROLLO ' ||
         ' AS ' ||
         ' SELECT MCF_CFO_CCC_CLI_PER_NUM_IDEN ' ||
         '      ,MCF_CFO_CCC_CLI_PER_TID_CODIGO ' ||
         '      ,MCF_CFO_CCC_NUMERO_CUENTA ' ||
         '      ,MCF_CFO_FON_CODIGO ' ||
         '      ,MCF_CFO_CODIGO ' ||
         '      ,MCF_CONSECUTIVO ' ||										-- rhenao
         '      ,MCF_FECHA ' ||
         '      ,MCF_TMF_MNEMONICO ' ||              
         '      ,MCF_SALDO_INVER ' ||
         '      ,MCF_SALDO_CAPITAL ' ||               
         '      ,MCF_SALDO_UNIDADES ' ||              
         '      ,MCF_SALDO_RENDIMIENTOS_RF ' ||
         '      ,MCF_SALDO_RENDIMIENTOS_RV ' ||  
         '      ,MCF_SALDO_RETEFUENTE ' ||            
         '      ,MCF_SALDO_INTERESES_PAGADOS ' ||
         ' FROM   MOVIMIENTOS_CUENTAS_FONDOS mcf1 ' ||
         ' WHERE  MCF1.MCF_FECHA >= ' || '''' || TO_CHAR(:QUE_FECHA,'DD-MON-YYYY') || '''' ||
         ' AND    MCF1.MCF_FECHA < ' || '''' || TO_CHAR(:QUE_FECHA + 1,'DD-MON-YYYY') || '''');
  :P_TABLA := 'TS_MOVIMIENTOS_FONDOS';
  return (TRUE);
end;

