      function CF_SEGMENTOFormula return VARCHAR2 is
  cli_segmento VARCHAR2(30);
begin
  SELECT BSC_DESCRIPCION
   INTO cli_segmento
   FROM CLIENTES,
        BI_SEGMENTACION_CLIENTES
  WHERE CLI_PER_TID_CODIGO = :MCF_CFO_CCC_CLI_PER_TID_CODIGO
    AND CLI_PER_NUM_IDEN = :MCF_CFO_CCC_CLI_PER_NUM_IDEN
    AND BSC_MNEMONICO = CLI_BSC_MNEMONICO
    AND BSC_BCC_MNEMONICO = CLI_BSC_BCC_MNEMONICO;

  return cli_segmento;
exception
	when others then
	  return null;
end;

      function CF_CATEGORIZACIONFormula return varchar2 is
  cli_categorizacion varchar2(35);
begin
  SELECT decode(CLI_PROFESIONAL,'S','CLIENTE PROFESIONAL MERCADO','N','CLIENTE INVERSIONISTA','Sin Informacion') 
    into cli_categorizacion
    FROM CLIENTES
  WHERE CLI_PER_TID_CODIGO = :MCF_CFO_CCC_CLI_PER_TID_CODIGO
    AND CLI_PER_NUM_IDEN = :MCF_CFO_CCC_CLI_PER_NUM_IDEN
    ;

  return cli_categorizacion;
exception
	when others then
	  return null;
end;
